import './styles.css'
import useProgressBarStore from './useProgressBarStore'
import ProgressBar from './ProgressBar'

function ProgressBars() {
    const progressBars = useProgressBarStore((state) => state.progressBars)
    const addProgressBar = useProgressBarStore((state) => state.addProgressBar)

    return (
        <>
            <div>
                {progressBars.map(pb => (
                    <ProgressBar key={pb.id} id={pb.id} />
                ))}
            </div>
            <button onClick={addProgressBar}>+Add</button>
        </>
    )
}

export default ProgressBars
